-- ============================================================
-- SteuerBack — Fix: insert directly into public tables only
-- Run this in Supabase SQL Editor.
-- Skips auth.users entirely (handles conflicts that broke prev seeds).
-- ============================================================

-- ── 1. public.users ──────────────────────────────────────────
-- First make sure all auth users exist in public.users
-- (copies anyone in auth.users that's missing from public.users)
INSERT INTO public.users (id, email, role, created_at)
SELECT au.id, au.email, 'user', au.created_at
FROM auth.users au
WHERE au.id::text LIKE '11111111%'
ON CONFLICT (id) DO UPDATE SET email = EXCLUDED.email;

-- ── 2. public.profiles ───────────────────────────────────────
-- Create blank profile rows for anyone missing
INSERT INTO public.profiles (user_id)
SELECT u.id FROM public.users u
WHERE u.id::text LIKE '11111111%'
ON CONFLICT (user_id) DO NOTHING;

